  3→import { useState, useRef, useEffect, useCallback } from 'react';
  4→import s from './page.module.css';
  5→import { useVoiceEngine, type VoiceEngineReturn } from '@/hooks/useVoiceEngine';
  6→
  7→// ── Types ──────────────────────────────────────────────────────────────────────
  8→
  9→interface HistoryMsg { role: 'user' | 'omega'; text: string; }
 10→
 11→// ── Main ───────────────────────────────────────────────────────────────────────
 12→
 13→export default function Home() {
 14→  const historyRef      = useRef<HistoryMsg[]>([]);
 15→  const voiceRef        = useRef<VoiceEngineReturn | null>(null);
 16→
 17→  const [started,        setStarted]        = useState(false);
 18→  const [statusText,     setStatusText]     = useState('Idle');
 19→  const [lastUser,       setLastUser]       = useState('');
 20→  const [lastReply,      setLastReply]      = useState('Say something to begin.');
 21→  const [isStreaming, setIsStreaming] = useState(false);
 22→
 23→  // ── Chat handler (streams text progressively) ──────────────────────────────
 24→  const handleTranscript = useCallback(async (text: string) => {
 25→    setStatusText('Processing...');
 26→    setLastUser(text);
 27→    historyRef.current.push({ role: 'user', text });
 28→
 29→    try {
 30→      const res = await fetch('/api/chat', {
 31→        method: 'POST',
 32→        headers: { 'Content-Type': 'application/json' },
 33→        body: JSON.stringify({ user: text, history: historyRef.current.slice(0, -1), voiceMode: true }),
 34→      });
 35→
 36→      const reader = res.body!.getReader();
 37→      const dec = new TextDecoder();
 38→      let fullReply = '';
 39→      setIsStreaming(true);
 40→
 41→      while (true) {
 42→        const { value, done } = await reader.read();
 43→        if (done) break;
 44→        const chunk = dec.decode(value, { stream: true });
 45→
 46→        // Skip SSE status lines
 47→        if (chunk.startsWith('data: {"type":"status"')) continue;
 48→
 49→        fullReply += chunk;
 50→        setLastReply(fullReply.replace(/\*/g, '').trim());
 51→      }
 52→
 53→      setIsStreaming(false);
 54→      fullReply = fullReply.trim();
 55→
 56→      if (!fullReply || fullReply.toUpperCase().includes('IGNORE')) {
 57→        setStatusText('Listening...');
 58→        return;
 59→      }
 60→
 61→      historyRef.current.push({ role: 'omega', text: fullReply });
 62→      setLastReply(fullReply.replace(/\*/g, '').trim());
 63→
 64→      // TTS — speak the full response (speakText → enterFollowUp → restarts recognition via useEffect)
 65→      setStatusText('Speaking...');
 66→      await voiceRef.current?.speakText(fullReply);
 67→      setStatusText('Listening...');
 68→      // Safety net: ensure we're back in listening state after TTS
 69→      if (voiceRef.current && voiceRef.current.voiceState === 'dormant') {
 70→        voiceRef.current.wakeUp();
 71→      }
 72→    } catch {
 73→      setIsStreaming(false);
 74→      setStatusText('Network error');
 75→    }
 76→  }, []);
 77→
 78→  // ── Voice engine hook ──────────────────────────────────────────────────────
 79→  const voice = useVoiceEngine({
 80→    onTranscript: handleTranscript,
 81→    onTTSStart: () => setStatusText('Speaking...'),
 82→    onTTSEnd: () => setStatusText('Listening...'),
 83→    autoStart: false,
 84→  });
 85→
 86→  // Keep ref in sync so handleTranscript can call speakText
 87→  useEffect(() => {
 88→    voiceRef.current = voice;
 89→  }, [voice]);
 90→
 91→  // ── Start system ───────────────────────────────────────────────────────────
 92→  const startSystem = useCallback(() => {
 93→    setStarted(true);
 94→    voice.wakeUp();
 95→    setStatusText('Listening...');
 96→  }, [voice]);
 97→
 98→  const derivedStatus = (() => {
 99→    if (!started || isStreaming) return statusText;
100→    switch (voice.voiceState) {
101→      case 'dormant': return 'Monitoring...';
102→      case 'listening': return 'Listening...';
103→      case 'thinking': return 'Processing...';
104→      case 'speaking': return 'Speaking...';
105→      case 'followup': return 'Awaiting Input...';
106→      default: return statusText;
107→    }
108→  })();
109→
110→  // ── Derived CSS classes ─────────────────────────────────────────────────────
111→  const isActive = voice.voiceState !== 'dormant';
112→  const badgeClass = [s.badge, isActive ? s.badgeActive : ''].join(' ');
113→
114→  return (
115→    <div className={s.root}>
116→      <div className={s.header}>
117→        <div className={s.brand}>OmegA</div>
118→        <span className={badgeClass}>{derivedStatus}</span>
119→      </div>
120→
121→      <div className={s.panel}>
122→        {lastUser && <div className={s.userLine}>You: {lastUser}</div>}
123→        <div className={s.reply}>{lastReply}</div>
124→        {voice.interim && <div className={s.interim}>{voice.interim}</div>}
125→      </div>
126→
127→      <div className={s.controls}>
128→        {!started ? (
129→          <button className={s.primaryBtn} onClick={startSystem}>Start Listening</button>
130→        ) : (
131→          <button className={s.primaryBtn} onClick={voice.toggle}>
132→            {voice.voiceState === 'dormant' ? 'Start Listening' : 'Pause Listening'}
133→          </button>
134→        )}
135→      </div>
136→    </div>
137→  );
138→}
