 4→export interface ChatRequest {
 5→  user: string;
 6→  history?: { role: "user" | "omega"; text: string; timestamp?: string }[];
 7→  sessionId?: string;
 8→  voiceMode?: boolean;
 9→}
10→
11→export interface ChatResponse {
12→  reply?: string;
13→  response?: string;
14→  provider?: string;
15→  sessionId?: string;
16→}
17→
18→export async function chat(req: ChatRequest): Promise<ChatResponse> {
19→  const res = await fetch('/api/chat', {
20→    method: 'POST',
21→    headers: { 'Content-Type': 'application/json' },
22→    body: JSON.stringify(req),
23→  });
24→
25→  if (!res.ok) {
26→    const body = await res.json().catch(() => ({ error: res.statusText }));
27→    throw new Error((body as { error?: string }).error ?? `${res.status}`);
28→  }
29→
30→  return res.json() as Promise<ChatResponse>;
31→}
32→
33→export async function chatStream(
34→  req: ChatRequest, 
35→  onChunk: (text: string) => void,
36→  onStatus?: (text: string) => void
37→): Promise<{ sessionId?: string; provider?: string }> {
38→  const res = await fetch('/api/chat', {
39→    method: 'POST',
40→    headers: { 'Content-Type': 'application/json' },
41→    body: JSON.stringify(req),
42→  });
43→
44→  if (!res.ok) {
45→    const body = await res.json().catch(() => ({ error: res.statusText }));
46→    throw new Error((body as { error?: string }).error ?? `${res.status}`);
47→  }
48→
49→  const sessionId = res.headers.get('X-Session-Id') || undefined;
50→  const provider = res.headers.get('X-Provider') || undefined;
51→
52→  if (!res.body) throw new Error("No response body");
53→
54→  const reader = res.body.getReader();
55→  const decoder = new TextDecoder();
56→  let buffer = "";
57→
58→  while (true) {
59→    const { value, done } = await reader.read();
60→    if (done) break;
61→    const chunkText = decoder.decode(value, { stream: true });
62→    buffer += chunkText;
63→
64→    // Split by SSE double newline if it looks like status events are active
65→    while (buffer.includes('\n\n')) {
66→      const idx = buffer.indexOf('\n\n');
67→      const line = buffer.slice(0, idx).trim();
68→      if (line.startsWith('data: {"type":"status"')) {
69→        try {
70→          const json = JSON.parse(line.slice(5));
71→          if (onStatus) onStatus(json.text);
72→          buffer = buffer.slice(idx + 2);
73→          continue;
74→        } catch {
75→          // fallback if parse fails
76→        }
77→      }
78→      break; // stop if front of buffer isn't a status event
79→    }
80→
81→    if (buffer && !buffer.startsWith('data: {"type":"status"')) {
82→      onChunk(buffer);
83→      buffer = "";
84→    }
85→  }
86→  
87→  // Flush remaining buffer
88→  const final = decoder.decode();
89→  buffer += final;
90→  if (buffer) onChunk(buffer);
91→
92→  return { sessionId, provider };
93→}
