 31→    SELECT LEFT(content, 6000) AS content, created_at
 32→    FROM omega_memory_entries
 33→    WHERE id = 'c4065da5-0000-0000-0000-000000000000'
 34→       OR id::text LIKE 'c4065da5%'
 35→    LIMIT 1
 36→  `.catch(() => [] as Row[]);
 37→
 38→  if ((anchor as Row[]).length === 0) {
 39→    anchor = await db`
 40→      SELECT LEFT(content, 6000) AS content, created_at
 41→      FROM omega_memory_entries
 42→      ORDER BY LENGTH(content) DESC
 43→      LIMIT 1
 44→    `.catch(() => [] as Row[]);
 45→  }
 46→
 47→  if ((anchor as Row[]).length === 0) return '';
