 95→async function pullRawContext(userMessage: string): Promise<string> {
 96→  const dbUrl = process.env.DATABASE_URL;
 97→  if (!dbUrl) return '(DATABASE_URL not set — no raw context available)';
 98→
 99→  const db = neon(dbUrl);
100→  const sections: string[] = [];
101→
102→  const anchor = await pullIdentityAnchor(db);
103→  if (anchor) sections.push(anchor);
104→  sections.push(YETTRAGRAMMATON);
105→
106→  const recent = await db`
107→    SELECT LEFT(content, 2500) AS content, created_at
108→    FROM omega_memory_entries
109→    ORDER BY created_at DESC
110→    LIMIT 20
111→  `.catch(() => [] as Row[]);
112→
113→  if ((recent as Row[]).length > 0) {
114→    sections.push('=== RECENT MEMORY ENTRIES ===');
115→    for (const r of recent as Row[]) sections.push(`[${r.created_at}]\n${r.content}`);
116→  }
117→
118→  const keywords = userMessage
119→    .toLowerCase()
120→    .replace(/[^a-z0-9 ]/g, ' ')
121→    .split(/\s+/)
122→    .filter(w => w.length > 3)
123→    .slice(0, 3);
124→
125→  if (keywords.length > 0) {
126→    const pattern = `%${keywords[0]}%`;
127→    const relevant = await db`
128→      SELECT LEFT(content, 2000) AS content, created_at
129→      FROM omega_memory_entries
130→      WHERE content ILIKE ${pattern}
131→      ORDER BY created_at DESC
132→      LIMIT 10
133→    `.catch(() => [] as Row[]);
134→
135→    if ((relevant as Row[]).length > 0) {
136→      sections.push('\n=== QUERY-RELEVANT ENTRIES ===');
137→      for (const r of relevant as Row[]) sections.push(`[${r.created_at}]\n${r.content}`);
138→    }
139→  }
140→
141→  const marginalia = await db`SELECT * FROM marginalia ORDER BY created_at DESC LIMIT 15`.catch(() => [] as Row[]);
142→  if ((marginalia as Row[]).length > 0) {
143→    sections.push('\n=== MARGINALIA ===');
144→    for (const m of marginalia as Row[]) sections.push(JSON.stringify(m));
145→  }
146→
147→  const events = await db`SELECT * FROM omega_events ORDER BY created_at DESC LIMIT 15`.catch(() => [] as Row[]);
148→  if ((events as Row[]).length > 0) {
149→    sections.push('\n=== SYSTEM EVENTS ===');
150→    for (const e of events as Row[]) sections.push(JSON.stringify(e));
151→  }
152→
153→  const improvements = await db`SELECT * FROM system_improvements ORDER BY created_at DESC LIMIT 10`.catch(() => [] as Row[]);
154→  if ((improvements as Row[]).length > 0) {
155→    sections.push('\n=== SYSTEM IMPROVEMENTS ===');
156→    for (const i of improvements as Row[]) sections.push(JSON.stringify(i));
157→  }
158→
159→  return sections.join('\n\n');
160→}
