339→        if (res?.length > 0) finalSessionId = res[0].id as string;
340→      } catch (e) {
341→        console.error('[OmegA] Session creation failed', e);
342→      }
343→    }
344→
345→    const encoder = new TextEncoder();
346→    const decoder = new TextDecoder();
347→
348→    if (dbUrl && finalSessionId) {
349→      const db = neon(dbUrl);
350→      try {
351→        await db`INSERT INTO omega_chat_messages (session_id, role, content) VALUES (${finalSessionId}, 'user', ${user})`;
352→      } catch (e) {
353→        console.error('[OmegA] DB write error', e);
354→      }
355→    }
